//SOUND_BEGIN
// SOUND_BEGIN
// =========================================================================
// Title: Red Cells
// Author: P_Malin
// Source: https://www.shadertoy.com/view/MsXXWH
// License: Creative Commons Attribution-NonCommercial-ShareAlike 3.0 Unported
//
// Note: Biological/Rhythmic ambient sound synthesis.
//       Adapted for Desktop GLSL Audio.
// =========================================================================

float Hash(float p)
{
    vec2 p2 = fract(vec2(p * 5.3983, p * 5.4427));
    p2 += dot(p2.yx, p2.xy + vec2(21.5351, 14.3137));
    return fract(p2.x * p2.y * 95.4337);
}

float SmoothNoise( float t )
{
    float noiset = t * 32.0;
    float tfloor = floor(noiset);
    float ffract = fract(noiset);

    float n0 = Hash(tfloor);
    float n1 = Hash(tfloor + 1.0);
    float blend = ffract * ffract * (3.0 - 2.0 * ffract);
    return mix(n0, n1, blend) * 2.0 - 1.0;
}

float FBM( float t, float persistence )
{
    float result = 0.0;
    float a = 1.0;
    float tot = 0.0;
    for(int i=0; i<3; i++)
    {
        result += SmoothNoise(t) * a;
        tot += a;
        t *= 2.02;
        a *= persistence;
    }
    return result / tot;
}

// -------------------------------------------------------------------------
// MAIN SOUND
// -------------------------------------------------------------------------

vec2 mainSound( in int samp, float time)
{
    // Battito cardiaco o pulsazione ritmica
    float fHeartBeat = pow(max(0.0, sin(time * 3.0)), 4.0) * 0.5;
    fHeartBeat += pow(max(0.0, sin(time * 3.0 + 0.3)), 4.0) * 0.3;

    // Rumore di fondo (flusso sanguigno)
    float fFlow = FBM(time * 0.5, 0.5) * 0.2;

    // Modulazione del rumore tramite il battito
    float fNoise = FBM(time * 40.0, 0.2 + fHeartBeat * 0.3);

    // Combinazione dei segnali
    float s = (fNoise * (0.2 + fHeartBeat)) + fFlow;

    // Stereo widen (leggero sfasamento per profondità)
    vec2 audio = vec2(s, s * 0.95 + 0.05 * Hash(time * 100.0));

    // Volume leggermente più basso per mantenere l'atmosfera cupa
    float fadeIn = smoothstep(0.0, 2.0, time);
    return clamp(audio * fadeIn * 0.4, -1.0, 1.0);
}
// SOUND_END
//SOUND_END

// =========================================================================
// Title: tm tiedie
// Author: tubeman
// Link: https://www.shadertoy.com/view/WX3cWS
// 
// License: Creative Commons Attribution-NonCommercial-ShareAlike 3.0 Unported
//          (CC BY-NC-SA 3.0) - https://creativecommons.org/licenses/by-nc-sa/3.0/
//
// Note: Adapted and modified for the "Surfaces Explorer" engine.
// =========================================================================

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f*f*(3.0-2.0*f); // Smoothstep interpolation

    float a = fract(sin(dot(i, vec2(12.9898, 78.233))) * 43758.5453);
    float b = fract(sin(dot(i + vec2(1, 0), vec2(12.9898, 78.233))) * 43758.5453);
    float c = fract(sin(dot(i + vec2(0, 1), vec2(12.9898, 78.233))) * 43758.5453);
    float d = fract(sin(dot(i + vec2(1, 1), vec2(12.9898, 78.233))) * 43758.5453);
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

mat2 rot(float a) {
    float c = cos(a), s = sin(a);
    return mat2(c,-s,s,c);
}

vec3 pal(float t) {
    return vec3(.5,.4,.5)+vec3(.5,.2,.5)
        *cos(6.28318*(vec3(1./2.,1./3.,5) * t + vec3(0,.54,0)-iTime*.4));
}

float getFreq(float f) {
    return texture(iChannel0, vec2(f,.25)).x;
}

vec3 tiedie(vec2 uv, float f) {
    float t = iTime * 0.4;
    float fft = getFreq(.001)*.35 - getFreq(.99)*.2;

    uv *= rot(t*.9);
    float amp = .3;
    float a = atan(uv.y+amp*sin(t),uv.x+amp*cos(t));

    uv.x += amp * cos(sin(a*f+t)*fft + t);
    uv.y += amp * sin(cos(a*f+t)*fft + t);

    return pal((1.-exp(-length(uv)*2.))*3.+.3);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = 1.*(fragCoord - 0.5 * iResolution.xy) / iResolution.y;
    vec3 col = tiedie(uv, 4.);
    vec3 col2 = tiedie(uv, 220.);

    col = mix(col, col2, .2);
    col = pow(col, vec3(2));
    col += vec3(.4,.4,.1)*(exp(-length(uv+.2*vec2(cos(iTime*.4),sin(iTime*.4)))*1.));
    col += .05 * (noise(uv * 400.)-.5);

    fragColor = vec4(col, 1.0);
}
